const fs = require('fs');
const path = require('path');

const UPLOAD_DIR = path.resolve(__dirname, '../uploads');

// ensure folder exists
const ensureDir = (folderPath) => {
    if (!fs.existsSync(folderPath)) {
        fs.mkdirSync(folderPath, { recursive: true });
    }
};

// save file
exports.saveFile = (buffer, filename, folder = '') => {

    const targetDir = path.join(UPLOAD_DIR, folder);

    ensureDir(targetDir);

    const filePath = path.join(targetDir, filename);

    fs.writeFileSync(filePath, buffer);

    return {
        url: `http://localhost:5000/uploads/${folder ? folder + '/' : ''}${filename}`,
        public_id: `${folder ? folder + '/' : ''}${filename}`
    };
};

exports.deleteFile = (public_id)=>{

    const filePath = path.resolve(UPLOAD_DIR,public_id);

    if(!fs.existsSync(filePath)){
        throw new Error('File not found');
    }
    fs.unlinkSync(filePath);
};